      out.write("\n");
      out.write("		function normalizeUserSearchText(value){\n");
      out.write("			return $.trim((value || \"\"));\n");
      out.write("		}\n");
      out.write("\n");
      out.write("		function toInt(value, fallback){\n");
      out.write("			var parsed = parseInt(value, 10);\n");
      out.write("			if(isNaN(parsed)){\n");
      out.write("				return (typeof fallback === \"number\") ? fallback : 0;\n");
      out.write("			}\n");
      out.write("			return parsed;\n");
      out.write("		}\n");
      out.write("\n");
      out.write("		function applyUserSearchFilter(){\n");
      out.write("			var keyword = normalizeUserSearchText(currentUserSearchKeyword).toLowerCase();\n");
      out.write("			$(\"#emps_table tbody tr\").each(function(){\n");
      out.write("				var row = $(this);\n");
      out.write("				var userIdText = normalizeUserSearchText(row.find(\"td:eq(2)\").text()).toLowerCase();\n");
      out.write("				var userNameText = normalizeUserSearchText(row.find(\"td:eq(3)\").text()).toLowerCase();\n");
      out.write("				var matched = (keyword === \"\")\n");
      out.write("					|| (userIdText.indexOf(keyword) !== -1)\n");
      out.write("					|| (userNameText.indexOf(keyword) !== -1);\n");
      out.write("				row.toggle(matched);\n");
      out.write("			});\n");
      out.write("		}\n");
