      out.write("					var stateRows = $.isArray(ext.deviceSyncStateRows) ? ext.deviceSyncStateRows : [];\n");
      out.write("					var successCount = 0;\n");
      out.write("					var failedCount = 0;\n");
      out.write("					var neverCount = 0;\n");
      out.write("					$.each(stateRows, function(index, row){\n");
      out.write("						if(!row){ return; }\n");
      out.write("						var status = $.trim((row.lastSyncStatus || \"\")).toUpperCase();\n");
      out.write("						if(status === \"SUCCESS\"){\n");
      out.write("							successCount++;\n");
      out.write("						}else if(status === \"FAILED\"){\n");
      out.write("							failedCount++;\n");
      out.write("						}else if(status === \"\" || status === \"NEVER\"){\n");
      out.write("							neverCount++;\n");
      out.write("						}\n");
      out.write("					});\n");
      out.write("					var message = $.trim(ext.message || \"\");\n");
      out.write("					var normalizedState = $.trim((state || \"\")).toUpperCase();\n");
      out.write("					if(normalizedState === \"\"){\n");
      out.write("						normalizedState = running ? \"RUNNING\" : \"IDLE\";\n");
      out.write("					}\n");
      out.write("					var text = \"SetUserToAllDevice | state=\" + normalizedState\n");
      out.write("						+ \" | users=\" + activeUsers\n");
      out.write("						+ \" | enrollRecords=\" + enrollRecords\n");
      out.write("						+ \" | queued=\" + totalQueued\n");
      out.write("						+ \" (setuserinfo=\" + setuserinfoQueued + \", cleanadmin=\" + cleanadminQueued + \")\"\n");
      out.write("						+ \" | devices=\" + stateRows.length\n");
      out.write("						+ \" (ok=\" + successCount + \", fail=\" + failedCount + \", never=\" + neverCount + \")\"\n");
      out.write("						+ \" | eta=\" + eta + \" sec\";\n");
      out.write("					if(normalizedState === \"FAILED\" && message !== \"\"){\n");
      out.write("						text += \" | reason=\" + message.substring(0, 120);\n");
      out.write("						if(message.length > 120){\n");
      out.write("							text += \"...\";\n");
      out.write("						}\n");
      out.write("					}\n");
      out.write("					text += \" | details: Status page\";\n");
      out.write("					$(\"#syncDbAllDevicesStatus\").text(text);\n");
      out.write("					$(\"#syncDbAllDevicesDeviceStatus\").empty();\n");
      out.write("				}\n");
      out.write("			});\n");
      out.write("		}\n");
